```typescript
// src/utils/discount.ts

/**
 * Returns the price after applying a percentage discount.
 * @param price - Original price (must be >= 0)
 * @param discountPercent - Discount percentage, 0–100 inclusive
 */
export function applyPercentageDiscount(price: number, discountPercent: number): number {
  if (price < 0) throw new RangeError("price must be >= 0");
  if (discountPercent < 0 || discountPercent > 100) {
    throw new RangeError("discountPercent must be between 0 and 100");
  }
  return price * (1 - discountPercent / 100);
}
```

